import java.util.*;

public class OptionalDemo {

    record Address(String street, String city, String country) {}
    record User(String name, String email, Address address) {}

    // ── Before Optional: NPE minefield ────────────────────────────
    static String getCityUnsafe(User user) {
        if (user != null && user.address() != null) {
            return user.address().city(); // still NPE if city is null
        }
        return "Unknown";
    }

    // ── With Optional: elegant chain ─────────────────────────────
    static String getCitySafe(User user) {
        return Optional.ofNullable(user)
            .map(User::address)
            .map(Address::city)
            .orElse("Unknown"); // default if any step is null/empty
    }

    // ── Repository pattern with Optional ─────────────────────────
    static Map<Long, User> db = Map.of(
        1L, new User("Alice", "alice@ex.com", new Address("123 Main", "Mumbai", "IN")),
        2L, new User("Bob",   "bob@ex.com",   null) // no address
    );

    static Optional<User> findById(long id) {
        return Optional.ofNullable(db.get(id));
    }

    static void processUser(long id) {
        // orElseThrow: explicit exception type
        User user = findById(id).orElseThrow(() -> new RuntimeException("User " + id + " not found"));
        System.out.println("Found: " + user.name());

        // ifPresent: side effect only if value exists
        findById(id).map(User::address).ifPresent(addr ->
            System.out.println("City: " + addr.city()));

        // flatMap: when the mapper also returns Optional
        String email = findById(id)
            .flatMap(u -> Optional.ofNullable(u.email())) // Optional<Optional<String>> → Optional<String>
            .filter(e -> e.contains("@"))
            .orElse("no-email");
        System.out.println("Email: " + email);
    }

    public static void main(String[] args) {
        System.out.println(getCitySafe(null));                          // Unknown
        System.out.println(getCitySafe(db.get(1L)));                   // Mumbai
        System.out.println(getCitySafe(db.get(2L)));                   // Unknown (address null)

        processUser(1L); // Found + city + email
        try { processUser(99L); } catch (RuntimeException e) {
            System.out.println(e.getMessage()); // User 99 not found
        }
    }
}

import java.util.*;
import java.util.stream.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.*;

public class ParallelStreams {

    // ── GOOD USE: CPU-bound, stateless, large data ─────────────────
    static long sumOfPrimes(int limit) {
        return IntStream.rangeClosed(2, limit)
            .parallel() // split across ForkJoinPool threads
            .filter(n -> {
                if (n < 2) return false;
                for (int i = 2; i <= Math.sqrt(n); i++)
                    if (n % i == 0) return false;
                return true;
            })
            .asLongStream()
            .sum();
    }

    // ── BAD USE: shared mutable state → wrong results ─────────────
    static int parallelCountBroken(List<Integer> list) {
        int[] count = {0}; // NOT thread-safe
        list.parallelStream().forEach(x -> count[0]++); // race condition!
        return count[0]; // will be wrong
    }

    // ── FIX: use thread-safe aggregation ─────────────────────────
    static long parallelCountSafe(List<Integer> list) {
        return list.parallelStream().count(); // stream handles this safely
    }

    // ── Custom ForkJoinPool (when commonPool is too small) ────────
    static List<String> parallelProcessWithCustomPool(List<String> items) throws Exception {
        ForkJoinPool customPool = new ForkJoinPool(4); // 4 threads
        try {
            return customPool.submit(() ->
                items.parallelStream()
                    .map(String::toUpperCase)
                    .collect(Collectors.toList())
            ).get();
        } finally {
            customPool.shutdown();
        }
    }

    // ── Timing comparison ─────────────────────────────────────────
    static void benchmark() {
        int limit = 1_000_000;

        long t1 = System.currentTimeMillis();
        long seq = IntStream.rangeClosed(2, limit).filter(n -> {
            for (int i = 2; i <= Math.sqrt(n); i++) if (n%i==0) return false;
            return n >= 2;
        }).count();
        System.out.println("Sequential: " + (System.currentTimeMillis()-t1) + "ms, primes=" + seq);

        t1 = System.currentTimeMillis();
        long par = IntStream.rangeClosed(2, limit).parallel().filter(n -> {
            for (int i = 2; i <= Math.sqrt(n); i++) if (n%i==0) return false;
            return n >= 2;
        }).count();
        System.out.println("Parallel:   " + (System.currentTimeMillis()-t1) + "ms, primes=" + par);
    }

    public static void main(String[] args) throws Exception {
        System.out.println("Sum of primes up to 100: " + sumOfPrimes(100)); // 1060

        List<Integer> nums = new ArrayList<>(Collections.nCopies(1000, 1));
        System.out.println("Safe count: " + parallelCountSafe(nums)); // 1000

        List<String> result = parallelProcessWithCustomPool(Arrays.asList("a", "b", "c"));
        System.out.println("Custom pool result: " + result); // [A, B, C]

        benchmark();
    }
}

