import java.util.*;

public class Q1 {
    record Address(String city, String country) {}
    record User(String name, Address address) {}

    static String getFormattedAddress(User user) {
        Optional<Address> addrOpt = Optional.ofNullable(user).map(User::address);
        Optional<String> city    = addrOpt.map(Address::city).filter(s -> !s.isBlank());
        Optional<String> country = addrOpt.map(Address::country).filter(s -> !s.isBlank());

        if (city.isEmpty()) return "Address Unknown";
        return city.get() + country.map(c -> ", " + c).orElse("");
    }

    public static void main(String[] args) {
        System.out.println(getFormattedAddress(new User("A", new Address("Mumbai", "India"))));
        System.out.println(getFormattedAddress(new User("B", new Address("London", null))));
        System.out.println(getFormattedAddress(new User("C", null)));
        System.out.println(getFormattedAddress(null));
    }
}

