import java.util.*;
import java.util.stream.*;

public class Q2 {
    static long countVowelWords(List<String> words, boolean parallel) {
        Stream<String> stream = parallel ? words.parallelStream() : words.stream();
        return stream
            .filter(w -> !w.isEmpty() && "aeiou".indexOf(Character.toLowerCase(w.charAt(0))) >= 0)
            .count();
    }

    public static void main(String[] args) {
        List<String> words = Arrays.asList(
            "apple", "banana", "orange", "grape", "elderberry",
            "fig", "avocado", "blueberry", "cherry", "apricot"
        );
        long seq = countVowelWords(words, false);
        long par = countVowelWords(words, true);
        System.out.println("Sequential: " + seq);
        System.out.println("Parallel:   " + par);
        System.out.println("Match: " + (seq == par));
    }
}

