import java.util.*;
import java.util.stream.*;

public class Q3 {
    static List<Integer> doubleAll(List<Integer> numbers) {
        // FIX: use collect() — parallel stream safely combines partial results
        return numbers.parallelStream()
            .map(n -> n * 2)
            .collect(Collectors.toList()); // thread-safe aggregation
    }

    public static void main(String[] args) {
        List<Integer> input = IntStream.rangeClosed(1, 10).boxed().collect(Collectors.toList());
        List<Integer> output = doubleAll(input);
        Collections.sort(output);
        System.out.println(output);
        System.out.println("Size: " + output.size());
    }
}
